#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, x;
        scanf("%d %d %d", &N, &K, &x);
        int p[K];
        for (int i = 0; i < K; i++) {
            scanf("%d", &p[i]);
        }
        int max = 0, min = 1000000001;
        for (int i = 0; i < K; i++) {
            if (p[i] > max) max = p[i];
            if (p[i] < min) min = p[i];
        }
        int sum = 0;
        for (int i = 0; i < K; i++) {
            sum += p[i];
        }
        int start = max + 1;
        for (int i = 0; i < N - K; i++) {
            sum += start;
            start++;
            if (start - min > x) break;
        }
        printf("%d\n", sum);
    }
    return 0;
}

