import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int x = sc.nextInt();
            int[] p = new int[K];
            for (int i = 0; i < K; i++) {
                p[i] = sc.nextInt();
            }
            int max = 0, min = 1000000001;
            for (int i = 0; i < K; i++) {
                if (p[i] > max) max = p[i];
                if (p[i] < min) min = p[i];
            }
            int sum = 0;
            for (int i = 0; i < K; i++) {
                sum += p[i];
            }
            int start = max + 1;
            for (int i = 0; i < N - K; i++) {
                sum += start;
                start++;
                if (start - min > x) break;
            }
            System.out.println(sum);
        }
    }
}

