    const p = input().split(' ').map(Number);
    let max = Math.max(...p);
    let min = Math.min(...p);
    let sum = p.reduce((a, b) => a + b, 0);
    let start = max + 1;
    for (let j = 0; j < N - K; j++) {
        sum += start;
        start++;
        if (start - min > x) break;
    }
    console.log(sum);
}
